.detail-header {
  padding: 12px;
  background: linear-gradient(to right, #667eea, #764ba2);
  color: white;
  border-bottom: 1px solid #e2e8f0;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.detail-title-row {
  display: flex;
  align-items: center;
  gap: 12px;
  flex: 1;
}

.detail-title {
  display: flex;
  align-items: center;
  gap: 8px;

  span {
    font-weight: bold;
    font-size: 16px;
  }
}

.detail-actions {
  display: flex;
  gap: 8px;
  margin-left: auto;
}

.delete-btn {
  background: rgba(255, 255, 255, 0.2);
  border: 1px solid rgba(255, 255, 255, 0.3);
  color: white;
  padding: 6px 10px;
  border-radius: 4px;
  cursor: pointer;
  font-size: 16px;
  transition: all 0.2s ease;

  &:hover {
    background: rgba(255, 255, 255, 0.3);
    border-color: rgba(255, 255, 255, 0.5);
  }

  &:active {
    transform: scale(0.95);
  }
}

.detail-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px;

  &::-webkit-scrollbar {
    width: 6px;
  }

  &::-webkit-scrollbar-track {
    background: #f0f4f8;
  }

  &::-webkit-scrollbar-thumb {
    background: #cbd5e0;
    border-radius: 3px;

    &:hover {
      background: #a0aec0;
    }
  }
}

.info-section {
  margin-bottom: 20px;
  padding-bottom: 16px;
  border-bottom: 1px solid #e2e8f0;

  &:last-child {
    border-bottom: none;
    margin-bottom: 0;
    padding-bottom: 0;
  }
}

.section-title {
  font-weight: bold;
  font-size: 14px;
  color: #2d3748;
  margin-bottom: 12px;
  padding-bottom: 6px;
  border-bottom: 2px solid #667eea;
}

.info-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: 12px;
}

.info-item {
  display: flex;
  flex-direction: column;
  gap: 4px;

  .label {
    font-weight: bold;
    color: #4a5568;
    font-size: 12px;
  }

  .value {
    color: #2d3748;
    font-size: 13px;
    word-break: break-word;
  }
}

.effects-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.effect-item {
  padding: 10px;
  background: #f7fafc;
  border-left: 3px solid #cbd5e0;
  border-radius: 4px;

  &.增益 {
    border-left-color: #48bb78;
    background: rgba(72, 187, 120, 0.05);
  }

  &.减益 {
    border-left-color: #e53e3e;
    background: rgba(229, 62, 62, 0.05);
  }

  &.特殊 {
    border-left-color: #667eea;
    background: rgba(102, 126, 234, 0.05);
  }
}

.effect-name {
  font-weight: bold;
  color: #2d3748;
  margin-bottom: 4px;
}

.effect-type {
  font-size: 12px;
  font-weight: bold;
  display: inline-block;
  padding: 2px 6px;
  border-radius: 3px;
  margin-bottom: 4px;

  .增益 & {
    background: #c6f6d5;
    color: #22543d;
  }

  .减益 & {
    background: #fed7d7;
    color: #742a2a;
  }

  .特殊 & {
    background: #dbeafe;
    color: #1e3a8a;
  }
}

.effect-info {
  font-size: 13px;
  color: #4a5568;
  margin-bottom: 6px;
}

.effect-meta {
  display: flex;
  gap: 12px;
  font-size: 11px;
  color: #718096;

  span {
    display: flex;
    gap: 4px;
  }
}

.arts-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.art-item {
  padding: 12px;
  background: #f7fafc;
  border: 1px solid #e2e8f0;
  border-radius: 4px;
}

.art-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
  flex-wrap: wrap;
}

.art-name {
  font-weight: bold;
  color: #2d3748;
  flex: 1;
}

.art-type {
  font-size: 11px;
  font-weight: bold;
  padding: 2px 6px;
  border-radius: 3px;
  white-space: nowrap;

  &.心法 {
    background: #dbeafe;
    color: #1e3a8a;
  }

  &.攻击 {
    background: #fed7d7;
    color: #742a2a;
  }

  &.咒法 {
    background: #fce7f3;
    color: #831843;
  }

  &.身法 {
    background: #ddd6fe;
    color: #3730a3;
  }

  &.护体 {
    background: #c6f6d5;
    color: #22543d;
  }

  &.其他 {
    background: #f3e8ff;
    color: #581c87;
  }
}

.art-quality {
  font-size: 12px;
  color: #718096;
  background: #edf2f7;
  padding: 2px 6px;
  border-radius: 3px;
}

.art-info {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.info-row {
  display: flex;
  gap: 8px;
  font-size: 13px;

  .label {
    font-weight: bold;
    color: #4a5568;
    min-width: 60px;
  }

  .value {
    color: #2d3748;
    flex: 1;
    word-break: break-word;

    &.positive {
      color: #48bb78;
      font-weight: bold;
    }

    &.negative {
      color: #e53e3e;
      font-weight: bold;
    }
  }

  &.full-width {
    flex-direction: column;
  }

  &.highlight {
    background: rgba(102, 126, 234, 0.1);
    padding: 4px 8px;
    border-radius: 3px;
  }
}

// 紧凑布局样式
.info-section.compact {
  margin-bottom: 12px;
  padding-bottom: 12px;
}

.subsection-title {
  font-weight: bold;
  font-size: 12px;
  color: #4a5568;
  margin-bottom: 8px;
  padding-bottom: 4px;
  border-bottom: 1px solid #cbd5e0;
}

.compact-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
  gap: 8px;

  .info-row {
    font-size: 12px;
    gap: 4px;

    .label {
      min-width: 50px;
      font-size: 11px;
    }

    .value {
      font-size: 12px;
    }

    &.full-width {
      grid-column: 1 / -1;
      flex-direction: row;
      gap: 6px;
      align-items: center;
      padding: 4px 0;
      min-height: auto;

      .label {
        font-weight: bold;
        min-width: auto;
        flex-shrink: 0;
      }

      .value {
        flex: 1;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
        line-height: 1.2;
      }
    }
  }
}

